        { id: 2, name: 'Product 2', price: 39.99, image: 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400' },
        { id: 3, name: 'Product 3', price: 49.99, image: 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400' }
